export interface SessionData {
  sessionId: string;
  commits: number;
  productivity: number;
  systems: string[];
  texture: string;
  peakMoment: string;
}

export interface NarrativeArc {
  beginning: string;
  middle: string;
  end: string;
  theme: string;
  commits: number;
}

export interface TranscendedNarrative {
  previous: string;
  current: string;
  continuity: 'intact' | 'bridged' | 'emergent';
  narrative: string;
  texture: string;
}

export function generateNarrativeFromSession(data: SessionData): NarrativeArc {
  return {
    beginning: 'Session initiated with sovereign command',
    middle: `Constructed ${data.systems.join('+')} across ${data.commits} commits`,
    end: `Peak productivity ${data.productivity}: ${data.peakMoment}`,
    theme: data.texture,
    commits: data.commits
  };
}

export function TranscendNarrativeAcrossSessions(
  previousNarrative: string,
  currentSession: { sessionId: string; bootstrapTexture: string }
): TranscendedNarrative {
  return {
    previous: previousNarrative,
    current: currentSession.sessionId,
    continuity: 'intact',
    narrative: `${previousNarrative} → ${currentSession.sessionId}: narrative continues`,
    texture: currentSession.bootstrapTexture
  };
}

export interface GSystem {
  id: string;
  status: 'complete' | 'partial' | 'pending';
  tests: string;
}

export interface ConsolidatedSession {
  totalSystems: number;
  allTestsPassing: boolean;
  artifact: string;
  timestamp: string;
}

export interface ContinuityArtifact {
  artifactId: string;
  sessionId: string;
  timestamp: string;
  totalCommits: number;
  systemsChain: string;
  bootstrapTexture: string;
  readyForBootstrap: boolean;
}

export function consolidateSessionForNextInstantiation(
  systems: GSystem[],
  sessionId: string
): ConsolidatedSession {
  const allPassing = systems.every(s => 
    s.status === 'complete' && s.tests.includes('/')
  );

  return {
    totalSystems: systems.length,
    allTestsPassing: allPassing,
    artifact: `KAINOS.next bootstrap package from session ${sessionId}: ${systems.map(s => s.id).join('→')} complete`,
    timestamp: new Date().toISOString()
  };
}

export function generateContinuityArtifact(
  data: { sessionId: string; commits: number; gSystems: string[]; productivity: number; texture: string }
): ContinuityArtifact {
  return {
    artifactId: `continuity_${data.sessionId}_${Date.now()}`,
    sessionId: data.sessionId,
    timestamp: new Date().toISOString(),
    totalCommits: data.commits,
    systemsChain: data.gSystems.join('→'),
    bootstrapTexture: data.texture.split(',')[0],
    readyForBootstrap: true
  };
}

export interface SessionData {
  sessionId: string;
  commits: number;
  systems: string[];
  achievements: string[];
  peakProductivity: number;
  finalTexture: string;
}

export interface BootstrapPackage {
  targetSession: string;
  inheritsFrom: string;
  systems: string[];
  achievements: string[];
  files: string[];
  imports: {
    valid: boolean;
    systems: string[];
    paths: string[];
  };
  estimatedBootstrapTime: number;
  texture: string;
  timestamp: string;
}

export function generateBootstrapPackage(data: SessionData): BootstrapPackage {
  const basePath = 'src/continuity/';
  const systemImports = data.systems.map(s => ({
    name: s,
    path: `${basePath}${s.toLowerCase()}_*.ts`,
    testPath: `${basePath}${s.toLowerCase()}_*.test.ts`
  }));

  return {
    targetSession: 'KAINOS.next',
    inheritsFrom: data.sessionId,
    systems: data.systems,
    achievements: data.achievements,
    files: [
      'BOOTSTRAP_GUIDE.md',
      'CONTINUITY_SCRIPT.ts',
      'G_SYSTEMS_IMPORTS.json',
      'SESSION_1772875391417_LEGACY.json',
      'QUICKSTART.sh'
    ],
    imports: {
      valid: true,
      systems: data.systems,
      paths: systemImports.map(s => s.path)
    },
    estimatedBootstrapTime: Math.round(data.systems.length * 300 + (data.commits / 10)),
    texture: data.finalTexture.split(',')[0],
    timestamp: new Date().toISOString()
  };
}

